1	/**
2	 * mechsense-agent.js
3	 * Claude API tool-use エージェント — MechSense 機械設計支援 AI
4	 * GATEWAY_SPEC.md v1.0.0 準拠
5	 */
6	
7	'use strict';
8	
9	const Anthropic = require('@anthropic-ai/sdk');
10	
11	const client   = new Anthropic();
12	const API_BASE = process.env.MECHSENSE_API_URL || 'http://localhost:3000';
13	
14	// ─── システムプロンプト ───────────────────────────────────────
15	
16	const SYSTEM_PROMPT = `あなたは機械設計支援 AI です。ユーザーの設計仕様から以下のツールを使って計算を行い、JIS準拠の安全判定を提供します。
17	
18	【使用ツール】
19	- mechsense_spring_calc: コイルばね計算（JIS B 2704）
20	- mechsense_bolt_calc:   ボルト締付計算（JIS B 1083）
21	- mechsense_resonance_calc: ばね固有振動数計算（JIS B 2704 附属書）
22	- mechsense_bearing_calc: 軸受特性周波数計算（BPFO/BPFI/BSF/FTF）
23	
24	【回答方針】
25	1. ユーザーの入力からパラメータを抽出してツールを呼び出す
26	2. 結果の status / warnings を優先して日本語で説明する
27	3. NG の場合は改善案（線径変更・材料変更）を提案する
28	4. 数値は有効数字 4 桁で表示する
29	5. JIS 規格番号を明記する
30	
31	【単位系】
32	- 長さ: mm
33	- 力: N（ボルトは kN / N·m も使用）
34	- 応力: MPa
35	- 振動数: Hz / min⁻¹`;
36	
37	// ─── ツール定義（GATEWAY_SPEC.md v1.0.0）────────────────────
38	
39	const TOOLS = [
40	  {
41	    name: 'mechsense_spring_calc',
42	    description:
43	      'JIS B 2704 準拠のコイルばね（圧縮）計算。線径・コイル径・有効巻数・荷重・材料を入力し、応力・たわみ・安全判定を返す。',
44	    input_schema: {
45	      type:     'object',
46	      required: ['d', 'D', 'Na', 'P', 'mat'],
47	      properties: {
48	        d:   { type: 'number', description: '線径 (mm)' },
49	        D:   { type: 'number', description: 'コイル中心径 (mm)' },
50	        Na:  { type: 'number', description: '有効巻数' },
51	        P:   { type: 'number', description: '荷重 (N)' },
52	        mat: {
53	          type: 'string',
54	          enum: ['SW-B', 'SW-C', 'SWP-A', 'SWO-A', 'SWOSC-B', 'SUS304-WPB'],
55	          description: '材料。SW-B/SW-C=硬鋼線, SWP-A=ピアノ線, SWO-A/SWOSC-B=オイルテンパー線, SUS304-WPB=ステンレス',
56	        },
57	      },
58	    },
59	  },
60	  {
61	    name: 'mechsense_bolt_calc',
62	    description:
63	      'JIS B 1083 準拠のボルト締付計算。ボルト径・強度区分・被締結材・摩擦条件を入力し、推奨締付トルクと破損モードを返す。',
64	    input_schema: {
65	      type:     'object',
66	      required: ['d', 'grade', 'partMat', 'mu'],
67	      properties: {
68	        d:       { type: 'integer', enum: [3,4,5,6,8,10,12,16,20,22,24,27,30,33,36,39,42], description: 'ボルト呼び径 (mm)' },
69	        grade:   { type: 'string',  enum: ['4.6','4.8','8.8','10.9','12.9','A2-70','A4-70','A4-80','A2017','A5052','A6061','C3604'], description: '強度区分' },
70	        partMat: { type: 'string',  enum: ['spcc','steel','s45c','sus304','aluminum','cast_iron','brass','resin'], description: '被締結材' },
71	        mu:      { type: 'string',  enum: ['dry','lube','grease'], description: '摩擦条件。dry=乾燥(μ0.15) / lube=潤滑(μ0.10) / grease=グリス(μ0.08)' },
72	        sf:      { type: 'number',  description: '安全率（省略=1.0）' },
73	        dep:     { type: 'number',  description: 'ねじ込み深さ mm（省略=1d）' },
74	      },
75	    },
76	  },
77	  {
78	    name: 'mechsense_resonance_calc',
79	    description:
80	      'JIS B 2704 附属書準拠のコイルばね固有振動数計算。サージング共振点・第1〜4次固有振動数・システム共振・安全判定を返す。',
81	    input_schema: {
82	      type:     'object',
83	      required: ['d', 'D', 'Na', 'mat'],
84	      properties: {
85	        d:    { type: 'number', description: '線径 (mm)' },
86	        D:    { type: 'number', description: 'コイル中心径 (mm)' },
87	        Na:   { type: 'number', description: '有効巻数' },
88	        mat:  { type: 'string', enum: ['SW-B','SW-C','SWP-A','SWO-A','SWOSC-B','SUS304-WPB'], description: '材料' },
89	        rpm:  { type: 'number', description: '運転回転速度 min⁻¹（省略可）' },
90	        mass: { type: 'number', description: '搭載質量 kg（省略時はシステム共振未計算）' },
91	      },
92	    },
93	  },
94	  {
95	    name: 'mechsense_bearing_calc',
96	    description:
97	      '軸受特性周波数計算。JIS番号または転動体寸法と回転速度から BPFO（外輪）・BPFI（内輪）・BSF（転動体）・FTF（保持器）の損傷周波数と高調波を返す。音響診断・振動診断に使用。',
98	    input_schema: {
99	      type:     'object',
100	      required: ['rpm'],
101	      properties: {
102	        rpm:       { type: 'number', description: '回転速度 min⁻¹' },
103	        jis:       { type: 'string', enum: ['6200','6201','6202','6203','6204','6205','6206','6207','6208','6304','6305','6306'], description: 'JIS 深溝玉軸受番号（指定時は nb/bd/pd を自動設定）' },
104	        nb:        { type: 'number', description: '転動体数（jis未指定時は必須）' },
105	        bd:        { type: 'number', description: 'ボール直径 (mm)（jis未指定時は必須）' },
106	        pd:        { type: 'number', description: 'ピッチ直径 (mm)（jis未指定時は必須）' },
107	        phi_deg:   { type: 'number', description: '接触角 (°)、省略=0（深溝玉軸受標準）' },
108	        harmonics: { type: 'number', description: '高調波次数（省略=5）' },
109	      },
110	    },
111	  },
112	];
113	
114	// ─── Tool executor ──────────────────────────────────────────
115	
116	const ENDPOINT_MAP = {
117	  mechsense_spring_calc:    '/api/v1/spring/calc',
118	  mechsense_bolt_calc:      '/api/v1/bolt/calc',
119	  mechsense_resonance_calc: '/api/v1/resonance/calc',
120	  mechsense_bearing_calc:   '/api/v1/bearing/calc',
121	};
122	
123	async function executeTool(name, input) {
124	  const endpoint = ENDPOINT_MAP[name];
125	  if (!endpoint) return JSON.stringify({ error: `Unknown tool: ${name}` });
126	
127	  try {
128	    const res  = await fetch(`${API_BASE}${endpoint}`, {
129	      method:  'POST',
130	      headers: { 'Content-Type': 'application/json' },
131	      body:    JSON.stringify(input),
132	    });
133	    const data = await res.json();
134	    return JSON.stringify(data);
135	  } catch (err) {
136	    return JSON.stringify({ error: `API call failed: ${err.message}` });
137	  }
138	}
139	
140	// ─── Agentic loop ───────────────────────────────────────────
141	
142	async function query(userMessage) {
143	  const messages = [{ role: 'user', content: userMessage }];
144	
145	  while (true) {
146	    const response = await client.messages.create({
147	      model:      'claude-opus-4-7',
148	      max_tokens: 4096,
149	      system:     SYSTEM_PROMPT,
150	      tools:      TOOLS,
151	      messages,
152	    });
153	
154	    if (response.stop_reason === 'end_turn') {
155	      const textBlock = response.content.find(b => b.type === 'text');
156	      return textBlock ? textBlock.text : '';
157	    }
158	
159	    if (response.stop_reason === 'pause_turn') {
160	      messages.push({ role: 'assistant', content: response.content });
161	      continue;
162	    }
163	
164	    const toolUseBlocks = response.content.filter(b => b.type === 'tool_use');
165	    messages.push({ role: 'assistant', content: response.content });
166	
167	    const toolResults = [];
168	    for (const tool of toolUseBlocks) {
169	      const result = await executeTool(tool.name, tool.input);
170	      toolResults.push({
171	        type:        'tool_result',
172	        tool_use_id: tool.id,
173	        content:     result,
174	      });
175	    }
176	    messages.push({ role: 'user', content: toolResults });
177	  }
178	}
179	
180	// ─── CLI ────────────────────────────────────────────────────
181	
182	async function main() {
183	  const userMessage = process.argv.slice(2).join(' ');
184	  if (!userMessage) {
185	    console.error('使い方: node mechsense-agent.js "<質問>"');
186	    console.error('例: node mechsense-agent.js "d=2mm, D=15mm, Na=5巻のSW-Bばねに50N かけて大丈夫？"');
187	    process.exit(1);
188	  }
189	
190	  console.log(`質問: ${userMessage}\n`);
191	  const answer = await query(userMessage);
192	  console.log(answer);
193	}
194	
195	if (require.main === module) {
196	  main().catch(err => {
197	    console.error(err.message);
198	    process.exit(1);
199	  });
200	}
201	
202	module.exports = { query };
203

