    input_schema: {
      type:     'object',
      required: ['d', 'grade', 'partMat', 'mu'],
      properties: {
        d:       { type: 'integer', enum: [3,4,5,6,8,10,12,16,20,22,24,27,30,33,36,39,42], description: 'ボルト呼び径 (mm)' },
        grade:   { type: 'string',  enum: ['4.6','4.8','8.8','10.9','12.9','A2-70','A4-70','A4-80','A2017','A5052','A6061','C3604'], description: '強度区分' },
        partMat: { type: 'string',  enum: ['spcc','steel','s45c','sus304','aluminum','cast_iron','brass','resin'], description: '被締結材' },
        mu:      { type: 'string',  enum: ['dry','lube','grease'], description: '摩擦条件。dry=乾燥(μ0.15) / lube=潤滑(μ0.10) / grease=グリス(μ0.08)' },
        sf:      { type: 'number',  description: '安全率（省略=1.0）' },
        dep:     { type: 'number',  description: 'ねじ込み深さ mm（省略=1d）' },
      },
    },
  },
  {
    name: 'mechsense_resonance_calc',
    description:
      'JIS B 2704 附属書準拠のコイルばね固有振動数計算。サージング共振点・第1〜4次固有振動数・システム共振・安全判定を返す。',
    input_schema: {
      type:     'object',
      required: ['d', 'D', 'Na', 'mat'],
      properties: {
        d:    { type: 'number', description: '線径 (mm)' },
        D:    { type: 'number', description: 'コイル中心径 (mm)' },
        Na:   { type: 'number', description: '有効巻数' },
        mat:  { type: 'string', enum: ['SW-B','SW-C','SWP-A','SWO-A','SWOSC-B','SUS304-WPB'], description: '材料' },
        rpm:  { type: 'number', description: '運転回転速度 min⁻¹（省略可）' },
        mass: { type: 'number', description: '搭載質量 kg（省略時はシステム共振未計算）' },
      },
    },
  },
  {
    name: 'mechsense_bearing_calc',
    description:
      '軸受特性周波数計算。JIS番号または転動体寸法と回転速度から BPFO（外輪）・BPFI（内輪）・BSF（転動体）・FTF（保持器）の損傷周波数と高調波を返す。音響診断・振動診断に使用。',
    input_schema: {
      type:     'object',
      required: ['rpm'],
      properties: {
        rpm:       { type: 'number', description: '回転速度 min⁻¹' },
        jis:       { type: 'string', enum: ['6200','6201','6202','6203','6204','6205','6206','6207','6208','6304','6305','6306'], description: 'JIS 深溝玉軸受番号（指定時は nb/bd/pd を自動設定）' },
        nb:        { type: 'number', description: '転動体数（jis未指定時は必須）' },
        bd:        { type: 'number', description: 'ボール直径 (mm)（jis未指定時は必須）' },
        pd:        { type: 'number', description: 'ピッチ直径 (mm)（jis未指定時は必須）' },
        phi_deg:   { type: 'number', description: '接触角 (°)、省略=0（深溝玉軸受標準）' },
        harmonics: { type: 'number', description: '高調波次数（省略=5）' },
      },
    },
  },
];

// ─── Tool executor ──────────────────────────────────────────

const ENDPOINT_MAP = {
  mechsense_spring_calc:    '/api/v1/spring/calc',
  mechsense_bolt_calc:      '/api/v1/bolt/calc',
  mechsense_resonance_calc: '/api/v1/resonance/calc',
  mechsense_bearing_calc:   '/api/v1/bearing/calc',
};

async function executeTool(name, input) {
  const endpoint = ENDPOINT_MAP[name];
  if (!endpoint) return JSON.stringify({ error: `Unknown tool: ${name}` });

  try {
    const res  = await fetch(`${API_BASE}${endpoint}`, {
      method:  'POST',
      headers: { 'Content-Type': 'application/json' },
      body:    JSON.stringify(input),
    });
    const data = await res.json();
    return JSON.stringify(data);
  } catch (err) {
    return JSON.stringify({ error: `API call failed: ${err.message}` });
  }
}

// ─── Agentic loop ───────────────────────────────────────────

async function query(userMessage) {
  const messages = [{ role: 'user', content: userMessage }];

  while (true) {
    const response = await client.messages.create({
      model:      'claude-opus-4-7',
      max_tokens: 4096,
      system:     SYSTEM_PROMPT,
      tools:      TOOLS,
      messages,
    });

    if (response.stop_reason === 'end_turn') {
      const textBlock = response.content.find(b => b.type === 'text');
      return textBlock ? textBlock.text : '';
    }

    if (response.stop_reason === 'pause_turn') {
      messages.push({ role: 'assistant', content: response.content });
      continue;
    }

    const toolUseBlocks = response.content.filter(b => b.type === 'tool_use');
    messages.push({ role: 'assistant', content: response.content });

    const toolResults = [];
    for (const tool of toolUseBlocks) {
      const result = await executeTool(tool.name, tool.input);
      toolResults.push({
        type:        'tool_result',
        tool_use_id: tool.id,
        content:     result,
      });
    }
    messages.push({ role: 'user', content: toolResults });
  }
}

// ─── CLI ────────────────────────────────────────────────────

async function main() {
  const userMessage = process.argv.slice(2).join(' ');
  if (!userMessage) {
    console.error('使い方: node mechsense-agent.js "<質問>"');
    console.error('例: node mechsense-agent.js "d=2mm, D=15mm, Na=5巻のSW-Bばねに50N かけて大丈夫？"');
    process.exit(1);
  }

  console.log(`質問: ${userMessage}\n`);
  const answer = await query(userMessage);
  console.log(answer);
}

if (require.main === module) {
  main().catch(err => {
    console.error(err.message);
    process.exit(1);
  });
}

module.exports = { query };

