/**
 * verify-mechsense-resonance.js
 * mechsense-core.js Resonance モジュール 検証スクリプト
 *
 * 実行: node verify-mechsense-resonance.js
 */

'use strict';
const MechSense = require('../mechsense-core.js');

let pass = 0, fail = 0;

function assert(label, actual, expected, tol) {
  if (expected === null) {
    if (actual === null) {
      console.log(`  ✅ ${label}`);
      pass++;
    } else {
      console.log(`  ❌ ${label}  actual=${actual}  expected=null`);
      fail++;
    }
  } else if (typeof expected === 'boolean') {
    if (actual === expected) {
      console.log(`  ✅ ${label}`);
      pass++;
    } else {
      console.log(`  ❌ ${label}  actual=${actual}  expected=${expected}`);
      fail++;
    }
  } else if (typeof expected === 'string') {
    if (actual === expected) {
      console.log(`  ✅ ${label}`);
      pass++;
    } else {
      console.log(`  ❌ ${label}  actual="${actual}"  expected="${expected}"`);
      fail++;
    }
  } else {
    const tolerance = tol !== undefined ? tol : 0.005;  // 0.5% default
    const rel = Math.abs(actual - expected) / (Math.abs(expected) || 1);
    if (rel <= tolerance) {
      console.log(`  ✅ ${label}  (${actual.toFixed(4)})`);
      pass++;
    } else {
      console.log(`  ❌ ${label}  actual=${actual.toFixed(4)}  expected=${expected}  rel_err=${(rel*100).toFixed(2)}%`);
      fail++;
    }
  }
}

const R = MechSense.Resonance;

// ─────────────────────────────────────────────────────────────────
// Case 1: 基準ケース（SW-B, d=2, D=15, Na=5）
// fn = (2000) / (2π × 5 × 225) × √(78500×1000/7.85) = 895 Hz
// ─────────────────────────────────────────────────────────────────
console.log('\n[Case 1] 基準ケース SW-B d=2 D=15 Na=5');
{
  const r = R.calc({ d: 2, D: 15, Na: 5, mat: 'SW-B' });
  assert('error = null',          r.error,        null);
  // fn = 2000/(2π×5×225) × √(78500×1000/7.85) ≈ 895 Hz
  assert('fn_surge ≈ 895 Hz',    r.fn_surge,     895.0, 0.01);
  // fn_surge_rpm = 895 × 60 = 53700
  assert('fn_surge_rpm ≈ 53700', r.fn_surge_rpm, 53700, 0.01);
  // k = 78500×16/(8×3375×5) = 9.304 N/mm
  assert('k ≈ 9.304 N/mm',       r.k,            9.304, 0.005);
  // f_safe_max = 895 × 0.7 = 626.5 Hz
  assert('f_safe_max ≈ 626.5',   r.f_safe_max,   895 * 0.7, 0.01);
  // fn_modes[0] = fn_surge
  assert('fn_modes[0] = fn_surge',   r.fn_modes[0], r.fn_surge, 0.001);
  // fn_modes[1] = 2×fn_surge
  assert('fn_modes[1] = 2×fn_surge', r.fn_modes[1], r.fn_surge * 2, 0.001);
  // no rpm → status = null
  assert('status = null (no rpm)',    r.status,   null);
  // m_spring > 0
  assert('m_spring > 0', r.m_spring > 0, true);
  // m_spring: ρ×1e-6 × (π/4)×4 × π×15×7 = 7.85e-6 × 3.1416 × 329.9 ≈ 0.00814 kg
  assert('m_spring ≈ 0.00814 kg', r.m_spring, 0.00814, 0.02);
}

// ─────────────────────────────────────────────────────────────────
// Case 2: 安全判定 SAFE（SW-C, d=4, D=30, Na=10, rpm=3000）
// fn = (4000)/(2π×10×900) × √(78500×1000/7.85) ≈ 223.7 Hz
// f_op = 3000/60 = 50 Hz, ratio = 50/223.7 ≈ 0.224 → SAFE
// ─────────────────────────────────────────────────────────────────
console.log('\n[Case 2] SAFE判定 SW-C d=4 D=30 Na=10 rpm=3000');
{
  const r = R.calc({ d: 4, D: 30, Na: 10, mat: 'SW-C', rpm: 3000 });
  assert('error = null', r.error, null);
  assert('fn_surge ≈ 223.7 Hz',  r.fn_surge,    223.7, 0.01);
  assert('f_op = 50 Hz',         r.f_op,         50.0, 0.001);
  assert('ratio ≈ 0.224',        r.ratio_surge,  50 / r.fn_surge, 0.001);
  assert('status = SAFE',        r.status,       'SAFE');
  assert('warnings.length = 0',  r.warnings.length === 0, true);
}

// ─────────────────────────────────────────────────────────────────
// Case 3: WARNING判定（同ばね, rpm=10000）
// f_op = 10000/60 = 166.7 Hz, ratio = 166.7/223.7 ≈ 0.745 → WARNING
// ─────────────────────────────────────────────────────────────────
console.log('\n[Case 3] WARNING判定 SW-C d=4 D=30 Na=10 rpm=10000');
{
  const r = R.calc({ d: 4, D: 30, Na: 10, mat: 'SW-C', rpm: 10000 });
  const f_op = 10000 / 60;
  const ratio = f_op / r.fn_surge;
  assert('ratio 0.65 < r < 0.8', ratio > 0.65 && ratio < 0.8, true);
  assert('status = WARNING',      r.status, 'WARNING');
  assert('warnings.length = 1',   r.warnings.length === 1, true);
}

// ─────────────────────────────────────────────────────────────────
// Case 4: DANGER判定（同ばね, rpm=15000）
// f_op = 15000/60 = 250 Hz, ratio = 250/223.7 ≈ 1.117 → DANGER
// ─────────────────────────────────────────────────────────────────
console.log('\n[Case 4] DANGER判定 SW-C d=4 D=30 Na=10 rpm=15000');
{
  const r = R.calc({ d: 4, D: 30, Na: 10, mat: 'SW-C', rpm: 15000 });
  const ratio = r.ratio_surge;
  assert('ratio > 0.8',          ratio > 0.8, true);
  assert('status = DANGER',      r.status, 'DANGER');
  assert('warnings.length = 1',  r.warnings.length === 1, true);
}

// ─────────────────────────────────────────────────────────────────
// Case 5: SUS304-WPB（d=3, D=25, Na=8）
// G=68500, ρ=7.93
// fn = 3000/(2π×8×625) × √(68500×1000/7.93) ≈ 280 Hz
// ─────────────────────────────────────────────────────────────────
console.log('\n[Case 5] SUS304-WPB d=3 D=25 Na=8');
{
  const r = R.calc({ d: 3, D: 25, Na: 8, mat: 'SUS304-WPB' });
  const expected_fn = (3 * 1e3) / (2 * Math.PI * 8 * 625) * Math.sqrt(68500 * 1e3 / 7.93);
  assert('error = null', r.error, null);
  assert(`fn_surge ≈ ${expected_fn.toFixed(1)} Hz`, r.fn_surge, expected_fn, 0.001);
  // SUS304 は G が低いので SW-B と同サイズより fn が低い
  assert('fn_SUS < fn_SWB_d3', r.fn_surge < 895, true);
}

// ─────────────────────────────────────────────────────────────────
// Case 6: システム共振（d=5, D=40, Na=12, mass=2.5 kg）
// k = 78500×625/(8×64000×12) ≈ 7.99 N/mm
// fn_sys = (1/2π) × √(7.99×1000/2.5) ≈ 9.0 Hz
// ─────────────────────────────────────────────────────────────────
console.log('\n[Case 6] システム共振 SW-B d=5 D=40 Na=12 mass=2.5kg');
{
  const r = R.calc({ d: 5, D: 40, Na: 12, mat: 'SW-B', mass: 2.5 });
  const k_exp = 78500 * 625 / (8 * 64000 * 12);  // ≈ 7.99 N/mm
  const fn_sys_exp = (1 / (2 * Math.PI)) * Math.sqrt(k_exp * 1000 / 2.5);
  assert('error = null',              r.error, null);
  assert(`k ≈ ${k_exp.toFixed(3)}`,  r.k, k_exp, 0.001);
  assert('fn_system not null',        r.fn_system !== null, true);
  assert(`fn_system ≈ ${fn_sys_exp.toFixed(2)} Hz`, r.fn_system, fn_sys_exp, 0.001);
  assert('fn_system_rpm not null',    r.fn_system_rpm !== null, true);
  assert('fn_system_rpm = fn_system×60', r.fn_system_rpm, r.fn_system * 60, 0.001);
}

// ─────────────────────────────────────────────────────────────────
// Case 7: mass なし → fn_system = null
// ─────────────────────────────────────────────────────────────────
console.log('\n[Case 7] mass未指定 → fn_system=null');
{
  const r = R.calc({ d: 3, D: 20, Na: 6, mat: 'SWP-A' });
  assert('fn_system = null',     r.fn_system, null);
  assert('fn_system_rpm = null', r.fn_system_rpm, null);
  assert('f_op = null',          r.f_op, null);
  assert('status = null',        r.status, null);
}

// ─────────────────────────────────────────────────────────────────
// Case 8: バリデーションエラー
// ─────────────────────────────────────────────────────────────────
console.log('\n[Case 8] バリデーションエラー');
{
  const r1 = R.calc({ d: -1, D: 15, Na: 5, mat: 'SW-B' });
  assert('d < 0 → error',   r1.error !== null, true);

  const r2 = R.calc({ d: 2, D: 15, Na: 5, mat: 'INVALID' });
  assert('bad mat → error', r2.error !== null, true);

  const r3 = R.calc({ d: 10, D: 15, Na: 5, mat: 'SW-B' });  // C = 1.5 < 2
  assert('C < 2 → error',   r3.error !== null, true);

  const r4 = R.calc({ d: 2, D: 0, Na: 5, mat: 'SW-B' });
  assert('D = 0 → error',   r4.error !== null, true);
}

// ─────────────────────────────────────────────────────────────────
// Case 9: DENSITY テーブル確認
// ─────────────────────────────────────────────────────────────────
console.log('\n[Case 9] DENSITY テーブル');
{
  assert('SW-B  density 7.85', R.DENSITY['SW-B'],       7.85, 0.001);
  assert('SUS304 density 7.93', R.DENSITY['SUS304-WPB'], 7.93, 0.001);
}

// ─────────────────────────────────────────────────────────────────
// Case 10: モジュール構造確認
// ─────────────────────────────────────────────────────────────────
console.log('\n[Case 10] モジュール構造');
{
  assert('version = 1.2.0', MechSense.version, '1.2.0');
  assert('Resonance.calc is function', typeof R.calc === 'function', true);
  assert('Resonance.DENSITY is object', typeof R.DENSITY === 'object', true);
  // Spring / Bolt 既存モジュールが壊れていないこと
  assert('Spring.calc still works', typeof MechSense.Spring.calc === 'function', true);
  assert('Bolt.calc still works',   typeof MechSense.Bolt.calc === 'function', true);
}

// ─────────────────────────────────────────────────────────────────
// 結果サマリー
// ─────────────────────────────────────────────────────────────────
console.log(`\n${'='.repeat(50)}`);
console.log(`テスト結果: ${pass} PASS / ${fail} FAIL`);
if (fail === 0) {
  console.log('✅ 全ケース PASS — Resonance モジュール実装は正確');
} else {
  console.log('❌ 失敗あり — 実装を確認してください');
  process.exit(1);
}
